payload.raw:
{
  "layout": "cards-3",
  "title": "深入调研",
  "subtitle": "",
  "cards": [
    {
      "icon": "cpu",
      "heading": "传感器成本瓶颈",
      "body": "国内缺乏低成本高精度柔性传感器技术，硬件成本居高不下。进口设备如 Meta 手套单价超万元且技术封闭，加剧教育实训与工业模拟场景落地阻力，亟需成本优化方案。"
    },
    {
      "icon": "code",
      "heading": "算法框架封闭性",
      "body": "开源或自主可控算法框架匮乏，制约定制化开发与迭代效率。现有方案难以满足自然交互能力需求，依赖传统手柄交互，阻碍具身智能研究方向的技术突破与快速验证。"
    },
    {
      "icon": "globe",
      "heading": "国产平台适配难",
      "body": "与国产 XR 平台（如 PICO）、工业仿真软件（如 Unity 中国版）接口适配方案不足。难以满足数据安全与生态融合需求，影响国产平台无缝对接及元宇宙产业高质量发展。"
    }
  ]
}

