payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第 1 月",
      "title": "材料制备与微结构设计",
      "description": "完成液态金属 - 聚氨酯复合薄膜制备，优化鱼网拓扑结构，实现应变系数>150 的高灵敏度传感材料基础构建。"
    },
    {
      "date": "第 2 月",
      "title": "硬件构建与信号标定",
      "description": "融合光纤传感与 IMU 单元，完成传感器阵列微结构组装与信号标定，确立 0.1mm 级空间分辨率硬件基础。"
    },
    {
      "date": "第 3 月",
      "title": "算法开发与模型训练",
      "description": "开发分层 CNN-LSTM 手势识别模型，结合时序滑动窗口分割与噪声抑制，实现毫秒级实时推理与>98.2% 准确率。"
    },
    {
      "date": "第 4 月",
      "title": "系统集成与反馈嵌入",
      "description": "集成多模态交互协议栈，嵌入微型电磁致动器与温控模块，构建感知 - 意图 - 反馈闭环，开发效率提升 60%。"
    },
    {
      "date": "第 5-6 月",
      "title": "场景验证与迭代优化",
      "description": "依托 H-Box 全息舱与李未可眼镜开展工业远程操控测试，进行用户体验迭代，形成可复用交互标准接口。"
    }
  ]
}

