payload.raw:
{
  "layout": "cards-3-featured",
  "title": "创新技术：自研高精度柔性传感器",
  "subtitle": "",
  "body": [
    {
      "type": "paragraph",
      "text": "本项目通过材料微观结构创新与混合传感架构设计，突破柔性传感器精度与寿命瓶颈。在实现高精度低延迟的同时大幅降低成本，具备显著工程适用性与学术影响力，支撑核心部件自主可控。"
    }
  ],
  "cards": [
    {
      "icon": "zap",
      "heading": "仿生材料结构",
      "body": "采用仿生“水膜 - 鱼网”结构液态金属导电薄膜与低迟滞聚氨酯复合介质。保障应变系数＞80 高灵敏度，实现 10 万次弯折后性能衰减＜5%，循环寿命提升 3 倍，解决传统材料易断裂难题。",
      "secondary": "循环寿命提升 3 倍"
    },
    {
      "icon": "target",
      "heading": "极致性能指标",
      "body": "混合传感架构融合光纤微形变检测与惯性测量单元姿态补偿，攻克单一传感漂移缺陷。达成 0.1mm 空间分辨率与＜50ms 系统延迟，成本较进口方案降低超 50%，有力支撑传感器成本优化目标。",
      "secondary": "成本较进口降低 50%"
    },
    {
      "icon": "book",
      "heading": "架构与学术验证",
      "body": "关键材料与结构设计发表于 IEEE 电子器件汇刊及 IEEE 传感器期刊。获领域内学者引用验证其工程适用性，确立技术领先性，为规模化量产奠定理论与实验基础。",
      "secondary": "IEEE 期刊发表验证"
    }
  ]
}

